form:Form.form:Scripts:
		function LoadForm()
{
	if (Ctrl('main').GetMode()=='NEW')
	{
		Ctrl('c_estado').SetXValue('P');
		Ctrl('f_estado').SetXValue(datetime2str(new Date()));
	}

	if (Ctrl('LIST'))
		estado = Ctrl('LIST').GetSelectAttrValue('c_estado');
	else
		estado = Ctrl('c_estado').GetXValue();

	if (estado == 'P')
	{
		CtrlEnabled('PLANIFICAR', false);
		CtrlEnabled('FINALIZAR', true);
		CtrlEnabled('CANCELAR', true);
		CtrlEnabled('EDIT', true);
		CtrlEnabled('DELETE', false);
		CtrlEnabled('CALCULAR_ASIST', true);  
		CtrlEnabled('EVAL_AS_DICT',Ctrl('main').GetMode()!='NEW' ? HayInscriptos():true);  	

		CtrlEnabled('INSCR_LEG',Ctrl('main').GetMode()!='NEW' ? HayEvaluaciones():true);       
		CtrlEnabled('INSCR_TER', true);  	 
	}
	if (estado == 'C')
	{
		CtrlEnabled('PLANIFICAR', true);
		CtrlEnabled('FINALIZAR', false);
		CtrlEnabled('CANCELAR', false);
		CtrlEnabled('EDIT', false);
		CtrlEnabled('DELETE', true);
	}
	if (estado == 'F')
	{
		CtrlEnabled('PLANIFICAR', false);
		CtrlEnabled('FINALIZAR', false);			
		CtrlEnabled('CANCELAR', false);  
		CtrlEnabled('DELETE', false);
		CtrlEnabled('EDIT', false);
		CtrlEnabled('CALCULAR_ASIST', false);
		CtrlEnabled('INSCR_LEG', false);       
		CtrlEnabled('INSCR_TER', false);
	}

	if (Ctrl('f_hoy'))
		Ctrl('f_hoy').SetXValue(date2str(new Date()));
}

function HayEvaluaciones()
{        
	if(Ctrl('main').GetMode() == 'LIST')
		evalua = Ctrl('LIST').GetSelectAttrValue('l_evalua');	                    
	else	 
	    evalua = Ctrl('l_evalua').GetXValue();

	if(evalua != "1")   
	{
		CtrlEnabled('EVAL_AS_DICT',false);     
		return true;
	}


    idDictado = "";  
	if(Ctrl('main').GetMode() == 'LIST')
		idDictado = Ctrl('LIST').GetXValue();
	else   
		idDictado = Ctrl('oi_dictado').GetXValue();

	np = GetProxy();
	nSQL = np.SQLService(); 	
	var qry = Ctrl("main").getResource("qry_eval_inscriptos");	

	var result = nSQL.GetXML(qry,"<DATA oi_dictado ='"+idDictado+"' />");

    return result.GetAttr('hayEvaluaciones') =='0' ? false : true;
}   

function HayInscriptos()
{ 
    idDictado = "";  
	if(Ctrl('main').GetMode() == 'LIST')
		idDictado = Ctrl('LIST').GetXValue();
	else   
		idDictado = Ctrl('oi_dictado').GetXValue();

	np = GetProxy();
	nSQL = np.SQLService(); 	
	var qry = Ctrl("main").getResource("qry_inscriptos");	

	var result = nSQL.GetXML(qry,"<DATA oi_dictado ='"+idDictado+"' />");

    return result.GetAttr('hayInscriptos') =='0' ? true : false;
}

function val_asistencia(me)
{
	if (Ctrl('l_controlar_asist').TypedValue() == true && me.GetXValue() == "")
	{
		me.SetError('Si el campo Controla Asistencia esta seleccionado, debe cargar un Porcentaje de Asistencia Mínimo');
		return false;
	}
	return true;		
}

function AddLegajos()
{ 
	idDictado = "";  
	if(Ctrl('main').GetMode() == 'LIST')
		idDictado = Ctrl('LIST').GetXValue();
	else   
		idDictado = Ctrl('oi_dictado').GetXValue();
	var param = "<DICTADO oi_dictado=\""+ idDictado + "\"/>";		
	openNewFlowWait('NucleusRH.Base.Capacitacion.Inscripcion.flow','INITLEGAJOS',param,new ObjectResult(), "L");			
}

function AddTerceros()
{  
idDictado = "";  
	if(Ctrl('main').GetMode() == 'LIST')
		idDictado = Ctrl('LIST').GetXValue();
	else   
		idDictado = Ctrl('oi_dictado').GetXValue();

	var param = "<DICTADO oi_dictado=\""+ idDictado+ "\"/>";		
	openNewFlowWait('NucleusRH.Base.Capacitacion.Inscripcion.Terceros.flow','INITTERCEROS',param,new ObjectResult(), "L");			
}

function ObjectResult()
{
	this.processResult = function()
	{
		//Ctrl('main').DoEvent("CHANGE");	
		LoadForm();
		if(Ctrl('main').GetMode() != 'LIST')
			Ctrl('main').DoEvent("CHANGE");
	}
}   

function ToList()
{                
	if (parseInt(Ctrl("iter_size").GetXValue(),10)<=1000)
		Ctrl("LISTA").DoEvent("showList");
	else
		showMess("Modo Lista", "Demasiados registros para ser mostrados en una lista.");
}
